CREATE TABLE public.audit_log (
    id bigint DEFAULT nextval('audit_log_id_seq'::regclass) NOT NULL,
    table_name text NOT NULL,
    action text NOT NULL,
    at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT audit_log_pkey PRIMARY KEY (id)
);
CREATE TABLE public.org (
    id bigint GENERATED ALWAYS AS IDENTITY,
    name text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT org_pkey PRIMARY KEY (id),
    CONSTRAINT org_name_key UNIQUE (name)
);

COMMENT ON TABLE public.org IS 'Organisations';
COMMENT ON COLUMN public.org.name IS 'Unique display name';
CREATE TABLE public.customer (
    id bigint GENERATED BY DEFAULT AS IDENTITY,
    org_id bigint NOT NULL,
    email text NOT NULL,
    first_name text,
    last_name text,
    full_name text GENERATED ALWAYS AS (((COALESCE(first_name, ''::text) || ' '::text) || COALESCE(last_name, ''::text))) STORED,
    balance numeric(12,2) DEFAULT 0 NOT NULL,
    status text DEFAULT 'active'::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT customer_pkey PRIMARY KEY (id),
    CONSTRAINT customer_email_key UNIQUE (email),
    CONSTRAINT customer_org_id_fkey FOREIGN KEY (org_id) REFERENCES org(id) ON DELETE CASCADE,
    CONSTRAINT customer_balance_chk CHECK (balance >= 0::numeric),
    CONSTRAINT customer_status_chk CHECK (status = ANY (ARRAY['active'::text, 'inactive'::text, 'banned'::text]))
);

COMMENT ON TABLE public.customer IS 'Customers belonging to an organisation';

