CREATE UNIQUE INDEX org_lower_name_uidx ON org USING btree (lower(name));

-- ======================================================================
-- Views
-- ======================================================================
CREATE VIEW public.active_customers AS
SELECT c.id,
    c.email,
    o.name AS org_name
   FROM customer c
     JOIN org o ON o.id = c.org_id
  WHERE c.status = 'active'::text;

COMMENT ON VIEW public.active_customers IS 'Active customers with their organisation name';
CREATE MATERIALIZED VIEW public.customer_counts AS
SELECT org_id,
    count(*) AS total
   FROM customer
  GROUP BY org_id;

