END;
$function$;
CREATE OR REPLACE PROCEDURE public.deactivate_customer(IN p_id bigint)
 LANGUAGE plpgsql
AS $procedure$
BEGIN
    UPDATE customer SET status = 'inactive' WHERE id = p_id;
END;
$procedure$;
CREATE OR REPLACE FUNCTION public.full_display_name(p_first text, p_last text)
 RETURNS text
 LANGUAGE sql
